#include <winsock2.h>
#pragma comment(lib, "ws2_32.lib")

using namespace std;

const int PORT = 8080;
const int MAX_PLAYERS = 16;
const float UPDATE_RATE = 0.05f; // 20 Hz
const float SHOOTING_COOLDOWN = 0.5f; // 500 ms

// Player structure
struct Player {
    int id;
    string name;
    vector<int> lastActions;
    bool isShooting;
};

vector<Player> players;
mutex playersMutex;

WSAData wsaData;
SOCKET listeningSocket = INVALID_SOCKET;

// Initialize the server
bool initServer() {
    // Initialize Winsock
    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
        cout << "WSAStartup failed with error: " << WSAGetLastError() << endl;
        return false;
    }

    // Create a socket
    listeningSocket = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (listeningSocket == INVALID_SOCKET) {
        cout << "socket creation failed with error: " << WSAGetLastError() << endl;
        return false;
    }

    // Bind the socket to the port number 8080
    sockaddr_in serverAddress;
    serverAddress.sin_family = AF_INET;
    serverAddress.sin_port = htons(PORT);
    serverAddress.sin_addr.s_addr = INADDR_ANY;

    if (bind(listeningSocket, (sockaddr*)&serverAddress, sizeof(serverAddress)) == SOCKET_ERROR) {
        cout << "socket bind failed with error: " << WSAGetLastError() << endl;
        return false;
    }

    // Listen for incoming connections
    if (listen(listeningSocket, MAX_PLAYERS) == SOCKET_ERROR) {
        cout << "listen failed with error: " << WSAGetLastError() << endl;
        return false;
    }

    return true;
}

// Process incoming UDP packets
void processPackets(vector<unsigned char> buffer, int length) {
    // Parse the packet data
    string action = "";
    int playerId = -1;
    float x = 0.0f, y = 0.0f, z = 0.0f;

    for (int i = 0; i < length; ++i) {
        switch (buffer[i]) {
            case 'A': // Action
                action = buffer[++i];
                break;
            case 'I': // Player ID
                playerId = stoi(string(buffer + ++i));
                break;
            case 'X': // Position X
                x = stof(string(buffer + ++i));
                break;
            case 'Y': // Position Y
                y = stof(string(buffer + ++i));
                break;
            case 'Z': // Position Z
                z = stof(string(buffer + ++i));
                break;
        }
    }

    // Handle the action
    if (action == "MOVE") {
        // Update the player position
        playersMutex.lock();
        for (auto& player : players) {
            if (player.id == playerId) {
                player.x = x;
                player.y = y;
                player.z = z;
            }
        }
        playersMutex.unlock();
    } else if (action == "SHOOT") {
        // Update the player shooting status
        playersMutex.lock();
        for (auto& player : players) {
            if (player.id == playerId) {
                player.isShooting = true;
            }
        }
        playersMutex.unlock();
    } else if (action == "END") {
        // Remove the player from the list
        playersMutex.lock();
        for (int i = 0; i < players.size(); ++i) {
            if (players[i].id == playerId) {
                players.erase(players.begin() + i);
                break;
            }
        }
        playersMutex.unlock();
    }
}

// Send updates to all connected clients
void sendUpdates() {
    vector<unsigned char> buffer;
    stringstream ss;

    // Build the update message for each player
    for (auto& player : players) {
        // Write the player ID and position to the stream
        ss << "UPDATE:" << player.id << ":" << player.x << "," << player.y << "," << player.z << ";";

        // Write the shooting status to the stream
        if (player.isShooting) {
            ss << "SHOOT;";
        }

        // Add a newline character at the end of the message
        ss << "\n";
    }

    // Convert the stringstream to a vector of bytes
    buffer = vector<unsigned char>(ss.str().begin(), ss.str().end());

    // Send the updates to all connected clients
    for (auto& client : clients) {
        sendto(client, (char*)buffer.data(), buffer.size(), 0, (sockaddr*)&serverAddress, sizeof(serverAddress));
    }
}

// Main game loop
void mainGameLoop() {
    while (true) {
        // Receive incoming UDP packets
        vector<unsigned char> buffer;
        int length = recvfrom(listeningSocket, (char*)buffer.data(), buffer.size(), 0, nullptr, nullptr);

        // Process the received packets
        if (length > 0) {
            processPackets(buffer, length);
        }

        // Update the player positions and send updates to clients
        playersMutex.lock();
        for (auto& player : players) {
            // Apply gravity to the player position
            player.y -= 9.8f * UPDATE_RATE;

            // If the player is shooting, reset the cool-down timer
            if (player.isShooting) {
                player.isShooting = false;
            }
        }
        playersMutex.unlock();

        sendUpdates();

        // Sleep for a short time to avoid high CPU usage
        this_thread::sleep_for(chrono::milliseconds(1));
    }
}